package com.establo.controller;import com.establo.dto.EmployeeDto;import com.establo.service.EmployeeService;import jakarta.validation.Valid;import lombok.RequiredArgsConstructor;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/api/employees") @RequiredArgsConstructor @PreAuthorize("hasRole('ADMIN')") public class EmployeeController {private final EmployeeService s;@GetMapping List<EmployeeDto> all(){return s.all();}@PostMapping ResponseEntity<EmployeeDto> create(@Valid @RequestBody EmployeeDto d){return ResponseEntity.status(201).body(s.create(d));}@PutMapping("/{id}") EmployeeDto update(@PathVariable Long id,@Valid @RequestBody EmployeeDto d){return s.update(id,d);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) void delete(@PathVariable Long id){s.delete(id);}}
